      var gestation_in_weeks;
      var estimatedDaysLeftInMs = new Date(EDD.getTime() - Date.now());
      gestation_in_weeks = 40 - estimatedDaysLeftInMs / (1000 * 60 * 60 * 24 * 7);
      return gestation_in_weeks;
    }
